// src/components/AddStudent.js
import React, { useState } from "react";
import axios from "axios";
import "./AddStudent.css"; // Make sure this CSS file is linked

const AddStudent = ({ setView }) => {
  const [studentData, setStudentData] = useState({
    name: "",
    year: "",
    section: "",
    timetable: [],
  });

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setStudentData({
      ...studentData,
      [name]: value,
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post("/api/students", studentData);
      alert("Student data added successfully");
      setView("studentData"); // Change to 'studentData' view after submit
    } catch (error) {
      alert("Error adding student data");
    }
  };

  return (
    <div className="add-student-form">
      <h2>Add Student</h2>
      <form onSubmit={handleSubmit}>
        <input
          type="text"
          name="name"
          placeholder="Student Name"
          value={studentData.name}
          onChange={handleInputChange}
          required
        />
        <input
          type="text"
          name="year"
          placeholder="Year"
          value={studentData.year}
          onChange={handleInputChange}
          required
        />
        <input
          type="text"
          name="section"
          placeholder="Section"
          value={studentData.section}
          onChange={handleInputChange}
          required
        />
        {/* Add timetable or other fields as needed */}
        <button type="submit">Submit</button>
      </form>
      <button onClick={() => setView("studentData")}>Go Back to Student Data</button>
    </div>
  );
};

export default AddStudent;
